select r.reg_date, r.img_description, r.is_paid, r.review_no, r.user_id,
r.company_no, r.product_no, r.rating, r.content, r.thumbnail_url, r.updated
from review r
where is_paid = 1 and product_no = #{productNo}
order by r.reg_date desc;


